/**
 * Unit tests for lifecycle/sync-session-end-dispatcher hook
 *
 * Tests sequential SessionEnd hook execution with run_on_fail semantics:
 * - session-metrics-summary (runOnFail: true — always runs)
 * - session-cleanup       (runOnFail: true — always runs)
 * - pattern-sync-push     (runOnFail: false — skipped if prior hook stops)
 *
 * Covers: run_on_fail always-runs contract, skip-after-stop,
 * systemMessage merging, error isolation, and continue: false propagation.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
  };
});

vi.mock('../../lifecycle/session-cleanup.js', () => ({
  sessionCleanup: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../lifecycle/pattern-sync-push.js', () => ({
  patternSyncPush: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

import { syncSessionEndDispatcher } from '../../lifecycle/sync-session-end-dispatcher.js';
import { sessionCleanup } from '../../lifecycle/session-cleanup.js';
import { patternSyncPush } from '../../lifecycle/pattern-sync-push.js';

import { createTestContext } from '../fixtures/test-context.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createSessionEndInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'SessionEnd',
    tool_name: '',
    session_id: 'test-session-end-001',
    tool_input: {},
    ...overrides,
  };
}

function makeSystemMessageResult(msg: string) {
  return { continue: true, systemMessage: msg };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

let testCtx: ReturnType<typeof createTestContext>;
describe('lifecycle/sync-session-end-dispatcher', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.resetAllMocks();
    // Re-establish default silent passing implementations after reset
    // sync-session-end-dispatcher has 2 hooks: session-cleanup (runOnFail) + pattern-sync-push
    vi.mocked(sessionCleanup).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(patternSyncPush).mockReturnValue({ continue: true, suppressOutput: true });
  });

  // -------------------------------------------------------------------------
  // All hooks pass silently
  // -------------------------------------------------------------------------

  describe('all hooks pass silently', () => {
    it('returns silent success when no hooks emit messages', () => {
      const input = createSessionEndInput();
      const result = syncSessionEndDispatcher(input, testCtx);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.systemMessage).toBeUndefined();
    });

    it('calls all two hooks', () => {
      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      // sync-session-end-dispatcher has 2 hooks (session-metrics-summary removed)
      expect(sessionCleanup).toHaveBeenCalled();
      expect(vi.mocked(sessionCleanup).mock.calls[0][0]).toEqual(input);
      expect(patternSyncPush).toHaveBeenCalled();
      expect(vi.mocked(patternSyncPush).mock.calls[0][0]).toEqual(input);
    });
  });

  // -------------------------------------------------------------------------
  // run_on_fail semantics: metrics-summary and session-cleanup always run
  // -------------------------------------------------------------------------

  describe('run_on_fail: always-runs contract', () => {
    it('session-cleanup runs even when it returns continue: false (runOnFail)', () => {
      // run_on_fail hooks can return continue: false but the dispatcher ignores it for skip logic
      vi.mocked(sessionCleanup).mockReturnValue({ continue: false });

      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      // pattern-sync-push must still run (runOnFail: false, but shouldContinue tracks non-runOnFail only)
      expect(patternSyncPush).toHaveBeenCalled();
    });

    it('dispatcher does not throw when a run_on_fail hook throws', () => {
      vi.mocked(sessionCleanup).mockImplementation(() => {
        throw new Error('cleanup failed');
      });

      const input = createSessionEndInput();
      expect(() => syncSessionEndDispatcher(input, testCtx)).not.toThrow();
    });

    it('logs run_on_fail hook failures as warn', () => {
      vi.mocked(sessionCleanup).mockImplementation(() => {
        throw new Error('cleanup crash');
      });

      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      expect(testCtx.log).toHaveBeenCalledWith(
        'sync-session-end-dispatcher',
        expect.stringContaining('session-cleanup failed'),
        'warn',
      );
    });
  });

  // -------------------------------------------------------------------------
  // Normal hook (pattern-sync-push) skip semantics
  // -------------------------------------------------------------------------

  describe('pattern-sync-push skip semantics', () => {
    it('runs pattern-sync-push when all prior hooks return continue: true', () => {
      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      expect(patternSyncPush).toHaveBeenCalled();
    });

    it('runs pattern-sync-push even when runOnFail hooks return continue: false (ignored for skip)', () => {
      // session-cleanup is runOnFail: true — its continue: false does NOT trigger skip logic
      vi.mocked(sessionCleanup).mockReturnValue({ continue: false });

      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      // pattern-sync-push STILL runs because shouldContinue only tracks non-runOnFail hooks
      expect(patternSyncPush).toHaveBeenCalled();
    });

    it('runs pattern-sync-push even when session-cleanup returns continue: false (also runOnFail)', () => {
      vi.mocked(sessionCleanup).mockReturnValue({ continue: false });

      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      expect(patternSyncPush).toHaveBeenCalled();
    });

    it('logs skip when pattern-sync-push itself would cause a subsequent normal hook to skip (no hooks after it)', () => {
      // pattern-sync-push returning continue: false would update shouldContinue,
      // but since there are no normal hooks after it, no hooks are skipped
      vi.mocked(patternSyncPush).mockReturnValue({ continue: false });

      const input = createSessionEndInput();
      const result = syncSessionEndDispatcher(input, testCtx);

      // Both hooks still ran
      expect(sessionCleanup).toHaveBeenCalled();
      expect(patternSyncPush).toHaveBeenCalled();
      // Result is still ok
      expect(result.continue).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // systemMessage collection and merging
  // -------------------------------------------------------------------------

  describe('systemMessage merging', () => {
    it('returns single systemMessage from one hook', () => {
      vi.mocked(sessionCleanup).mockReturnValue(
        makeSystemMessageResult('Cleanup: temp files removed.'),
      );

      const input = createSessionEndInput();
      const result = syncSessionEndDispatcher(input, testCtx);

      expect(result.systemMessage).toBe('Cleanup: temp files removed.');
    });

    it('merges systemMessages from multiple hooks', () => {
      vi.mocked(sessionCleanup).mockReturnValue(
        makeSystemMessageResult('Cleanup: temp files removed.'),
      );
      vi.mocked(patternSyncPush).mockReturnValue(
        makeSystemMessageResult('Patterns: synced to remote.'),
      );

      const input = createSessionEndInput();
      const result = syncSessionEndDispatcher(input, testCtx);

      expect(result.systemMessage).toContain('Cleanup: temp files removed.');
      expect(result.systemMessage).toContain('Patterns: synced to remote.');
    });

    it('result has continue: true when systemMessage is present', () => {
      vi.mocked(sessionCleanup).mockReturnValue(
        makeSystemMessageResult('Something happened.'),
      );

      const input = createSessionEndInput();
      const result = syncSessionEndDispatcher(input, testCtx);

      expect(result.continue).toBe(true);
    });
  });

  // -------------------------------------------------------------------------
  // Logging
  // -------------------------------------------------------------------------

  describe('logging', () => {
    it('logs "All SessionEnd hooks silent" when no messages collected', () => {
      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      // Check that at least one logHook call contains 'silent'
      const calls = vi.mocked(testCtx.log).mock.calls;
      const hasSilentLog = calls.some(
        ([name, msg]) => name === 'sync-session-end-dispatcher' && String(msg).includes('silent'),
      );
      expect(hasSilentLog).toBe(true);
    });

    it('logs merged message count when messages are collected', () => {
      vi.mocked(sessionCleanup).mockReturnValue(makeSystemMessageResult('A'));
      vi.mocked(patternSyncPush).mockReturnValue(makeSystemMessageResult('B'));

      const input = createSessionEndInput();
      syncSessionEndDispatcher(input, testCtx);

      const calls = vi.mocked(testCtx.log).mock.calls;
      const hasMergedLog = calls.some(
        ([name, msg]) => name === 'sync-session-end-dispatcher' && String(msg).includes('Merged'),
      );
      expect(hasMergedLog).toBe(true);
    });
  });
});
